import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Pinterest","description":"","frontmatter":{"title":"Pinterest","slug":"pinterest"},"headers":[],"relativePath":"marketer-hub/pinterest.md","filePath":"marketer-hub/pinterest.md"}'),n={name:"marketer-hub/pinterest.md"};function o(s,e,d,l,c,p){return a(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://pinterest.com" target="_blank" rel="noreferrer">Pinterest</a> is a visual discovery engine for finding ideas like recipes, home and style inspiration, and more. With billions of Pins on Pinterest, you&#39;ll always find ideas to spark inspiration. When you discover Pins you love, save them to boards to keep your ideas organized and easy to find.</p><h3 id="partner-capabilities" tabindex="-1">Partner capabilities <a class="header-anchor" href="#partner-capabilities" aria-label="Permalink to &quot;Partner capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Partner capabilities</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>- Ad Network - DSP - Publisher - RTB - Self Serve</td></tr><tr><td>Deep Linking</td><td>Supported</td></tr><tr><td>Attribution</td><td>- Click-Through Attribution - View-Through Attribution</td></tr><tr><td>Ad Campaign Types</td><td>- Acquisition campaigns - Retargeting campaigns</td></tr><tr><td>Ad Formats</td><td>Contact support at Pinterest for more information.</td></tr><tr><td>Click Types</td><td>- Server-side click</td></tr><tr><td>Supported Platforms</td><td>- iOS - Android - Windows - Mac OS - Unix - Tizen</td></tr><tr><td>Link Wrapping</td><td>Not Supported</td></tr><tr><td>Cost Ingestion Support</td><td>Supported</td></tr><tr><td>Cost Ingestion Types</td><td>via API (Beta)</td></tr><tr><td>Cost Time Zone</td><td>GMT</td></tr><tr><td>Cost Data Scheduling</td><td>[ 4, 9, 12, 18, 24, 36, 48, 72, 96, 120, 240, 360, 480, 720 ] in hours from midnight</td></tr><tr><td>Pricing Models</td><td>- CPC - CPM - CPA - CPV - CPL</td></tr><tr><td><a href="https://developers.pinterest.com/docs/conversions/conversions/" target="_blank" rel="noreferrer">v5 Conversions API</a></td><td>Supported</td></tr><tr><td>Data Sharing</td><td>Branch does not share Pinterest user-level data (view-through/click-through) with advertisers via Custom Exports, Webhook, or Data Integrations.</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>To enable Pinterest for your Branch account, you first need to:</p><ol><li><p>Create and <a href="./account-hub-overview.html">configure</a> your <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch</a> account.</p></li><li><p>Have Branch&#39;s Performance <a href="./packaging.html">product</a> enabled for your account.</p></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Admin, Analyst, Audience, or Campaign <a href="https://help.pinterest.com/en/business/article/share-and-manage-access-to-your-ad-accounts" target="_blank" rel="noreferrer">Business Access</a> to your Pinterest account.</p></li></ol><h2 id="enable-pinterest" tabindex="-1">Enable Pinterest <a class="header-anchor" href="#enable-pinterest" aria-label="Permalink to &quot;Enable Pinterest&quot;">​</a></h2><p>Use the steps in this section to enable the integration between Branch and Pinterest.</p><h3 id="_1-retrieve-ad-account-id-from-pinterest" tabindex="-1">1. Retrieve Ad Account ID from Pinterest <a class="header-anchor" href="#_1-retrieve-ad-account-id-from-pinterest" aria-label="Permalink to &quot;1. Retrieve Ad Account ID from Pinterest&quot;">​</a></h3><ol><li><p>Log in to your Pinterest Ads Manager account.</p></li><li><p>Navigate to <strong>Ads</strong> <strong>&gt;</strong> <strong>Account Overview</strong>.</p></li><li><p>Locate and note the Ad Account ID in the URL path.</p><ul><li>Ex: <code>ads.pinterest.com/advertiser/{ad_account_id}/?...</code></li></ul></li></ol><p>.png)</p><h3 id="_2-retrieve-conversion-token-from-pinterest" tabindex="-1">2. Retrieve Conversion Token from Pinterest <a class="header-anchor" href="#_2-retrieve-conversion-token-from-pinterest" aria-label="Permalink to &quot;2. Retrieve Conversion Token from Pinterest&quot;">​</a></h3><ol><li><p>If you do not have a Conversion Token already created, navigate to <strong>Account Overview &gt;</strong> <strong>Conversions</strong>.</p><ol start="4"><li>Select <strong>Set up API</strong> in the <strong>Conversions API</strong> section.</li><li>Select <strong>Generate new token</strong>.</li></ol></li><li><p>Use the <strong>copy</strong> icon to copy the Conversion Token.</p></li></ol><h3 id="_3-connect-pinterest-in-branch" tabindex="-1">3. Connect Pinterest in Branch <a class="header-anchor" href="#_3-connect-pinterest-in-branch" aria-label="Permalink to &quot;3. Connect Pinterest in Branch&quot;">​</a></h3><ol><li>Visit <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Ad Partners</a> in Branch.</li><li>Search for Pinterest.</li><li>Enter the Ad Account ID and Conversion Token from steps 1 and 2 into the corresponding fields.</li><li>Select <strong>Save</strong>.</li></ol><p>.png)</p><h3 id="_4-configure-postbacks" tabindex="-1">4. Configure Postbacks <a class="header-anchor" href="#_4-configure-postbacks" aria-label="Permalink to &quot;4. Configure Postbacks&quot;">​</a></h3><p>When a conversion/event attributed to an ad campaign occurs, Branch notifies the Ad partner of these events via <strong>postbacks</strong>.</p><p>Basic postbacks will be automatically activated for events like <strong>INSTALL</strong> and <strong>PURCHASE</strong> when you enable your ad partner.</p><p>After you connect Pinterest to Branch, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_pinterest?tab=postback" target="_blank" rel="noreferrer"><strong>Postback Config</strong></a> tab and set up the following event mappings between Pinterest and Branch.</p><h4 id="default-event-mappings" tabindex="-1">Default event mappings <a class="header-anchor" href="#default-event-mappings" aria-label="Permalink to &quot;Default event mappings&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Pinterest Event</th><th>Branch Event</th></tr></thead><tbody><tr><td>page_visit</td><td>- OPEN - INSTALL - REINSTALL - PAGEVIEW - WEB_SESSION_START</td></tr><tr><td>checkout</td><td>PURCHASE</td></tr><tr><td>view_category</td><td>- VIEW_ITEM - VIEW_ITEMS</td></tr><tr><td>add_to_cart</td><td>ADD_TO_CART</td></tr><tr><td>signup</td><td>COMPLETE_REGISTRATION</td></tr><tr><td>lead</td><td>- ADD_TO_WISHLIST - RESERVE - START_TRIAL - SUBSCRIBE</td></tr><tr><td>search</td><td>SEARCH</td></tr><tr><td>custom</td><td>{custom_event_name}</td></tr><tr><td>watch_video</td><td>N/A</td></tr></tbody></table><p>As best practice, Pinterest recommends toggling the <strong>All Events</strong> checkbox to enable sending Pinterest all in-app conversions. This allows Pinterest to report the full value the platform is driving to your app.</p><div class="tip custom-block"><p class="custom-block-title">Postbacks</p><p>For more details on configuring Postbacks, view our guides:</p><ul><li><a href="https://help.branch.io/marketer-hub/docs/basic-postback-configuration" target="_blank" rel="noreferrer">Basic Postback Configuration</a></li><li><a href="https://help.branch.io/developer-hub/docs/advanced-postback-configuration" target="_blank" rel="noreferrer">Advanced Postback Configuration</a></li><li><a href="https://help.branch.io/marketer-hub/docs/testing-postbacks?highlight=postback-testing" target="_blank" rel="noreferrer">Test Postbacks</a></li></ul></div><h3 id="_4-configure-attribution-windows" tabindex="-1">4. Configure attribution windows <a class="header-anchor" href="#_4-configure-attribution-windows" aria-label="Permalink to &quot;4. Configure attribution windows&quot;">​</a></h3><p>After configuring postbacks, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_pinterest?tab=attribution_windows" target="_blank" rel="noreferrer">Attribution Windows tab</a> to set windows by attribution type.</p><p>You can use custom attribution windows to match Pinterest&#39;s attribution windows. This overrides your <a href="https://dashboard.branch.io/configuration/attribution-windows" target="_blank" rel="noreferrer">app-level attribution windows</a>.</p><h3 id="_5-set-up-cost-data" tabindex="-1">5. Set up cost data <a class="header-anchor" href="#_5-set-up-cost-data" aria-label="Permalink to &quot;5. Set up cost data&quot;">​</a></h3><p>To set up cost ingestion for Pinterest, you will need to authenticate using your login for Pinterest.</p><ol><li>Use the <strong>Log in</strong> button to authenticate with Pinterest.</li><li>Select <strong>Save Authentication</strong>.</li></ol><p>.png)</p><h3 id="_6-validate-integration" tabindex="-1">6. Validate integration <a class="header-anchor" href="#_6-validate-integration" aria-label="Permalink to &quot;6. Validate integration&quot;">​</a></h3><p>After configuring attribution windows, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_pinterest?tab=postback_testing" target="_blank" rel="noreferrer">Postback Testing tab</a> to test your integration.</p><p><em>[Image: Test Postbacks]</em></p><h3 id="_7-create-a-branch-link" tabindex="-1">7. Create a Branch Link <a class="header-anchor" href="#_7-create-a-branch-link" aria-label="Permalink to &quot;7. Create a Branch Link&quot;">​</a></h3><p>If you are running paid advertising campaigns, you&#39;ll want to create a Branch <a href="https://help.branch.io/using-branch/docs/ad-links" target="_blank" rel="noreferrer">Ad Link</a> so we can accurately attribute resulting app conversions to the appropriate advertising partner.</p><p><em>[Image: Create Ad Links]</em></p><h3 id="_8-create-a-campaign" tabindex="-1">8. Create a campaign <a class="header-anchor" href="#_8-create-a-campaign" aria-label="Permalink to &quot;8. Create a campaign&quot;">​</a></h3><ol><li><p>Use a direct link to your website in the Destination URL field.</p><ol><li>Remove <code>$aaid_sha1={sha1_advertising_id}</code> from your Branch Link if your Destination URL goes to the Apple Store.</li><li>Remove <code>$idfa_sha1={sha1_advertising_id}</code> from your Branch Link if your Destination URL goes to the Google Play Store.</li><li>Select <strong>App</strong> under the <strong>Ad Destination</strong> dropdown if using a mobile deep link (more info <a href="https://help.pinterest.com/en/business/article/mobile-deep-links" target="_blank" rel="noreferrer">here</a>).</li></ol></li><li><p>Place your Branch Click Tracking Link in the <strong>URL</strong> field for the Pin Clicks Event Type.</p></li><li><p>Place your Branch Impression Tracking Link in the <strong>URL</strong> field for Impressions Event Type.</p></li></ol><p><em>[Image: Pinterest ad format selection with highlighted elements for website and tracking details.]</em>.png)</p><h3 id="_9-verify-data-sent" tabindex="-1">9. Verify data sent <a class="header-anchor" href="#_9-verify-data-sent" aria-label="Permalink to &quot;9. Verify data sent&quot;">​</a></h3><p>Once the above steps are complete, you are ready to start launching campaigns. Branch-attributed conversions enabled as postbacks will be sent to Pinterest if they were the last touch that drove the conversion.</p><p>To verify data is being sent from Branch to Pinterest, you can access <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Branch&#39;s Liveview Webhook Records</a>, and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad partner (3p)</td><td>equals</td><td><code>a_pinterest</code></td></tr></tbody></table><h4 id="verify-cost-data" tabindex="-1">Verify cost data <a class="header-anchor" href="#verify-cost-data" aria-label="Permalink to &quot;Verify cost data&quot;">​</a></h4><p>To verify that cost data is flowing into Branch, you need to have the following:</p><ul><li>Completed all implementation steps above.</li><li>Be live with campaigns running for the ad network.</li><li>Wait 24 hours for data to be pulled in.</li></ul><h2 id="troubleshoot" tabindex="-1">Troubleshoot <a class="header-anchor" href="#troubleshoot" aria-label="Permalink to &quot;Troubleshoot&quot;">​</a></h2><p>If you are running campaigns on Pinterest and having issues with Attribution on Branch, please check whether you are using correct tracking links:</p><ol><li>Link to the Apple AppStore or Google Play.</li><li>Click and Impression links, generated on Branch, configured as described below.</li></ol><h4 id="link-formatting-issues" tabindex="-1">Link formatting issues <a class="header-anchor" href="#link-formatting-issues" aria-label="Permalink to &quot;Link formatting issues&quot;">​</a></h4><p>Verify your link formatting is correct using the examples below.</p><p><strong>Click Tracking Link</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://branchster.app.link/9kLGbtxJo2?%243p=a_pinterest&amp;&amp;%24idfa_sha1={sha1_advertising_id}&amp;%24s2s=true&amp;~ad_set_id={ad_group_id}&amp;~ad_set_name={ad_group_name}&amp;~campaign={campaign_name}&amp;~campaign_id={campaign_id}&amp;~click_id={click_id}&amp;~creative_id={creative_id}&amp;~creative_name={creative_name}&amp;~secondary_publisher={publisher](https://branchster.app.link/9kLGbtxJo2?%243p=a_pinterest&amp;%24aaid_sha1={sha1_advertising_id}&amp;%24idfa_sha1={sha1_advertising_id}&amp;%24s2s=true&amp;~ad_set_id={ad_group_id}&amp;~ad_set_name={ad_group_name}&amp;~campaign={campaign_name}&amp;~campaign_id={campaign_id}&amp;~click_id={click_id}&amp;~creative_id={creative_id}&amp;~creative_name={creative_name}&amp;~secondary_publisher={publisher)</span></span></code></pre></div><p><strong>Impression Tracking Link</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://impression.link/impression?branch_key=key_live_hkDytPACtipny3N9XmnbZlapBDdj4WIL&amp;%243p=a_pinterest&amp;%24s2s=true&amp;%24aaid_sha1={sha1_advertising_id}&amp;~ad_set_id={ad_group_id}&amp;~ad_set_name={ad_group_name}&amp;~branch_ad_format=App%20Only&amp;~campaign={campaign_name}&amp;~campaign_id={campaign_id}&amp;~click_id={click_id}&amp;~creative_id={creative_id}&amp;~creative_name={creative_name}&amp;~feature=paid%20advertising&amp;~secondary_publisher={publisher](https://impression.link/impression?branch_key=key_live_hkDytPACtipny3N9XmnbZlapBDdj4WIL&amp;%243p=a_pinterest&amp;%24s2s=true&amp;%24aaid_sha1={sha1_advertising_id}&amp;~ad_set_id={ad_group_id}&amp;~ad_set_name={ad_group_name}&amp;~branch_ad_format=App%20Only&amp;~campaign={campaign_name}&amp;~campaign_id={campaign_id}&amp;~click_id={click_id}&amp;~creative_id={creative_id}&amp;~creative_name={creative_name}&amp;~feature=paid%20advertising&amp;~secondary_publisher={publisher)</span></span></code></pre></div><p>Pinterest uses server-to-server clicks, so make sure the following parameters are always present on the link:</p><ul><li><p><strong>%24s2s=true</strong></p><ul><li>Must be always present on the link.</li></ul></li><li><p><strong>%24aaid_sha1={sha1_advertising_id}</strong></p><ul><li>For Android campaigns only, must be removed from the link for iOS campaigns.</li></ul></li><li><p><strong>%24idfa_sha1={sha1_advertising_id}</strong></p><ul><li>For iOS campaigns only, must be removed from the link for Android campaigns.</li><li>Only one OS-specific Advertiser Identifier parameter must be on the link: either <strong>%24idfa_sha1</strong> for iOS or <strong>%24aaid_sha1</strong> for Android campaigns.</li></ul></li></ul><h4 id="advertiser-id-is-missing-from-url" tabindex="-1">Advertiser ID is missing from URL <a class="header-anchor" href="#advertiser-id-is-missing-from-url" aria-label="Permalink to &quot;Advertiser ID is missing from URL&quot;">​</a></h4><p>If your URL is missing the Ad Account ID, use the OS-specific Ad ID instead.</p><h4 id="both-advertiser-ids-present-in-the-url" tabindex="-1">Both Advertiser IDs present in the URL <a class="header-anchor" href="#both-advertiser-ids-present-in-the-url" aria-label="Permalink to &quot;Both Advertiser IDs present in the URL&quot;">​</a></h4><p>If both Advertiser IDs are present in the URL, keep only one OS-specific Ad ID.</p><h4 id="clicks-are-blocked-by-anti-fraud-rule-geo-conflict" tabindex="-1">Clicks are blocked by anti-fraud rule <code>GEO_CONFLICT</code> <a class="header-anchor" href="#clicks-are-blocked-by-anti-fraud-rule-geo-conflict" aria-label="Permalink to &quot;Clicks are blocked by anti-fraud rule `GEO_CONFLICT`&quot;">​</a></h4><p>If your clicks are getting blocked by Branch’s anti-fraud rule <code>GEO_CONFLICT</code>, this is because Pinterest currently can’t provide the user’s IP address. If you use a <code>GEO_CONFLICT</code> rule, we recommend either disabling it or not running on Pinterest until they are able to pass the client IP to MMPs.</p>',65)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
